/*
FUNCTIONS
------------------------------------------------------
*/

// Add item list to the corresponding div
function addList(divList, addInput){
	if(addInput.value === ""){
		alert("Enter item name");
	}
	else{
		const ul = divList.querySelector("ul");
		const li = document.createElement("li");
		li.className = "itemLabel";
		li.innerHTML = addInput.value;
		addInput.value = "";
		ul.appendChild(li);
		createRadioElement(li);
		createRemoveBtn(li);
	}
}

// Create remove button for a new item list
function createRemoveBtn(li){
	const remove = document.createElement("button");
	remove.className = "btn-icon-remove";
	if(li.className != "permanent"){
		li.appendChild(remove);
	}
	return li;
}

// Create radio boxes for a new item list
function createRadioElement(li){
	radio1 = document.createElement("input");
	radio1.setAttribute("type", "radio");
	radio1.setAttribute("id", "0");
	radio1.setAttribute("name", "radioItem" + count);
	
	radio2 = document.createElement("input");
	radio2.setAttribute("type", "radio");
	radio2.setAttribute("id", "1");
	radio2.setAttribute("name", "radioItem" + count);
	
	radio3 = document.createElement("input");
	radio3.setAttribute("type", "radio");
	radio3.setAttribute("id", "2");
	radio3.setAttribute("name", "radioItem" + count);
	
	space = document.createElement("span");
	space.setAttribute("innerHTML", "&nbsp;&nbsp");
	
	li.appendChild(radio1);
	li.appendChild(space);
	li.appendChild(radio2);
	li.appendChild(space);
	li.appendChild(radio3);
	
	count++;
	
	return li;
}


/*
GLOBAL VARIABLES
------------------------------------------------------
*/
count = 100


/*
HUMAN RESSOURCES DIV
------------------------------------------------------
*/
// Select the div
const HRdivList = document.querySelector(".HRitemList");

// create variables
const HRaddInput = document.querySelector("#HRaddItem");
const HRaddBtn = document.querySelector("#HRaddBtn");
const HRlistUl = document.querySelector(".HRlist");
const HRlis = HRlistUl.children;

// Add new item list with click
HRaddBtn.addEventListener("click", () => {
	addList(HRdivList, HRaddInput);
});

// Add new item list with keyboard
HRaddInput.addEventListener("keyup", (event) => {
	if(event.which === 13){
		addList(HRdivList, HRaddInput);
	}
});

// For each new item list, create a remove button
for(var i= 0 ; i < HRlis.length; i++){
	createRemoveBtn(HRlis[i]);
};

// Remove new added item from the list with click
HRdivList.addEventListener("click", (event) => {
	if(event.target.tagName === "BUTTON"){
		const button = event.target;
		const li = button.parentNode;
		const ul = li.parentNode;
		ul.removeChild(li);
	}
});


